mapper.select:
SELECT uid, companyName, bizRegNo, onlineSalesNo, tel, fax
FROM seller
WHERE uid = #{uid}

mapper.update:
UPDATE seller
SET companyName = #{companyName},
    onlineSalesNo = #{onlineSalesNo},
    tel = #{tel},
    fax = #{fax}
WHERE uid = #{uid}

mapper.select:
SELECT sales.sellerUid, COALESCE(reviews.averageRating, 0) AS averageRating, COALESCE(reviews.reviewCount, 0) AS reviewCount, sales.salesCount FROM ( SELECT p.sellerUid, COALESCE(SUM(CASE WHEN o.orderNo IS NOT NULL THEN oi.count ELSE 0 END), 0) AS salesCount FROM product p LEFT JOIN product_variant pv ON pv.prodNo = p.prodNo LEFT JOIN order_item oi ON oi.prodVariantId = pv.id LEFT JOIN `order` o ON o.orderNo = oi.orderNo AND o.status NOT IN ('CANCELLED', 'REFUNDED') WHERE p.sellerUid IN
#{sellerUid}
GROUP BY p.sellerUid ) sales LEFT JOIN ( SELECT p.sellerUid, AVG(r.rating) AS averageRating, COUNT(r.reviewNo) AS reviewCount FROM product p JOIN review r ON r.prodNo = p.prodNo WHERE p.sellerUid IN
#{sellerUid}
GROUP BY p.sellerUid ) reviews ON reviews.sellerUid = sales.sellerUid
